var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"큭크크, 이 쬐끄만 녀석들. 어디에 숨어있는 것이냐?","JPN":"くっくっくっ、チビどもめ。どこに隠れておる？","ENG":"Heh heh heh. You little things. Where are you hiding?","TWN":"哼哼，你們這些小東西，都給我躲到哪裡去了？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"잡히면 모조리 씹어 먹어주겠노라.","JPN":"捕まえたら容赦なくかぶりついてやる。","ENG":"If I catch you, I'll chomp down on you.","TWN":"被我抓到的話，我就把你們通通吞下肚！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"오오, 찾았다!","JPN":"おお、見つけたぞ！","ENG":"Ooo, found you!","TWN":"喔喔！找到了！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"으끄응…! 팔이 안 닿아! 조금만 더…!","JPN":"うんぐぐ……手が届かない！　もう少し……！","ENG":"*Groan...* I can't reach... Just a little farther...","TWN":"唔呃…！我的手不夠長！要再伸長一點…！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L8_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"…우앗!","JPN":"……うわっ！","ENG":"Wah!","TWN":"…哎呀！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"이게 무슨 소리죠?","JPN":"これはどういうことですか？","ENG":"What's this noise?","TWN":"這是什麼聲音？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"흐익!","JPN":"ひいっ！","ENG":"Heek!","TWN":"嗚嗚！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"여기에 대체 왜 컵이 깨져 있는 건가요?","JPN":"なぜここでグラスが割れているのですか？","ENG":"Why is this glass broken?","TWN":"這裡怎麼會有打破的杯子？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L15_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"그, 그건… 저 손님이 꼭 이 컵으로 마셔야 한다고 해서…","JPN":"そ、それは……あのお客さんが絶対にこのグラスで飲みたいって言うから……","ENG":"Th-that's... because that customer insisted he would use this glass...","TWN":"那個…那個客人就說一定要用這個杯子喝酒…"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L17_1","type":"dialog","speaker":"GUEST_VOICE_DRUNK_NULL","text":{"KOREA":"…으응? 나? 내가 그런 말을 했었던가?","JPN":"……うん？　俺？　俺そんなこと言ったっけ？","ENG":"Mm? Me? Did I say that?","TWN":"…喔？我嗎？我有說過這種話喔？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L18_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"뻔하네요. 또 숨겨둔 사탕 찾느라 온 찬장을 다 헤집고 다닌 거죠?","JPN":"聞くまでもないですね。\\nまた隠しておいたキャンディーを探して食器棚を漁っていたんですね？","ENG":"You're so transparent. You rummaged through the cupboard again, looking for hidden candy, didn't you?","TWN":"我用膝蓋想也知道，你是不是翻箱倒櫃地想找藏起來的糖果？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L19_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"게다가 다른 사람에게 책임을 덮어 씌우다뇨! 오늘 하루동안 단 거 전부 금지예요!","JPN":"しかも他の人に責任をなすりつけるなんて！\\n今日一日甘いものは禁止です！","ENG":"You also put the blame on someone else. You're banned from sweets today!","TWN":"竟然還想責任賴到客人頭上！罰你今天都不能再吃糖果！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L20_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"흐에엑!","JPN":"ほええっ！","ENG":"Heek!","TWN":"嗚嗚嗚！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L22_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"무, 무엄하다! 마왕인 이 몸을 통제하려 들다니!","JPN":"ぶ、無礼者！　魔王である吾輩の行動を制御しようとするなんて！","ENG":"H-how dare you? I'm a Demon Lord! You subject can't control me!","TWN":"大膽！竟然想控制本王！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"들어온 지 고작 일주일밖에 안 된 신입 하수인 주제에!","JPN":"入ってからたった一週間しか経っていない新人下僕のくせに！","ENG":"You've only been here for a week!","TWN":"你這個新人手下，進來不過才一個禮拜而已欸！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L26_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"신입이지만 매일 일도 안하고 먹을 것만 찾는 모모보단 가게에 보탬이 되고 있다고요.","JPN":"新人ですが、毎日仕事もせずに食べ物ばかり漁るモモよりは\\nお店に役立っていますよ。","ENG":"Be that as it may, but at least I work. And you, you just spend all day looking for food.","TWN":"我是新人沒錯，但我對這家店的貢獻比你大吧！你整天不做事，只知道找糖吃！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L27_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"제가 오기 전까지 손님들이 직접 술을 따라 마셨다는 얘기를 듣고 얼마나 놀랐는데요!","JPN":"私が入る前はお客様が直接お酒を注いで飲んでいたなんて話を聞いて、\\nびっくりしましたよ！","ENG":"I still can't believe that our customers had to get drinks on their own before I came along.","TWN":"當我聽到原來在我來之前，客人都是自己倒酒喝的，你知道我有多震驚嗎？！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"으으…….","JPN":"むう……","ENG":"Grr...","TWN":"呃……"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"몰라, 몰라! 이 몸은 산책이나 다녀와야겠도다!","JPN":"知らないもん！　吾輩は散歩にでも行ってくる！","ENG":"Sue me! I'm going out for fresh air!","TWN":"隨便你啦！本王要出去散散步！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L31_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"흥. 어차피 도움도 안 되는데 마음대로 하시죠.","JPN":"ふん。どうせ仕事の役に立たないですし、好きにしてください。","ENG":"Hmpf, why do I care? You're not helping even when you're here.","TWN":"哼，隨便你，反正你在店裡也只是幫倒忙！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"……아, 동전지갑은 챙겼어요?","JPN":"……あ、お財布は忘れてないですか？","ENG":"... Oh, are you taking your coin purse with you?","TWN":"……欸，有記得帶零錢包嗎？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"앗. 잊을 뻔했다. 고맙구나.","JPN":"あっ、忘れるところだった。助かるぞ。","ENG":"Ah! I almost forgot. Thank you.","TWN":"對吼，差點忘了，謝啦～"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"……다녀오마, 흥!","JPN":"……行ってくる、ふん！","ENG":"... I'm going. Hmpf!","TWN":"……我出門囉，哼！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"길이나 조심해서 다녀요, 흥!","JPN":"車に気をつけてくださいね、ふん！","ENG":"You'd better not get lost. Hmpf!","TWN":"路上小心喔，哼！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L40_1","type":"dialog","speaker":"GUEST_VOICE_WOMEN_NULL","text":{"KOREA":"니콜. 여기 진 토닉 한 잔.","JPN":"ニコル、ジントニックを一杯頼む。","ENG":"Nicole, a gin and tonic, please.","TWN":"妮可，一杯琴通寧。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"앗, 어서 오세요. 지난번처럼 유자 넣어드려요?","JPN":"あっ、いらっしゃいませ。この前と同じく、ゆず入りでいいですか？","ENG":"Oh, hi. Want a slice of citron in it, just like last time?","TWN":"喔，歡迎光臨，跟上次一樣加柚子嗎？"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"GUEST_VOICE_WOMEN_NULL","text":{"KOREA":"그거 좋지.","JPN":"もちろん。","ENG":"Sure.","TWN":"好啊！"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"GUEST_VOICE_WOMEN_NULL","text":{"KOREA":"두 사람은 오늘도 사이가 좋아 보이네.","JPN":"二人は今日も相変わらず仲良しだな。","ENG":"It's always good to see you two getting along so well.","TWN":"你們感情還是這麼好呢。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"그럴 리가요. 말썽만 일으켜서 손이 많이 간다니까요.","JPN":"まさかそんな。トラブルばかり起こして手のかかる子なんですよ。","ENG":"You're joking, right? She's such a handful.","TWN":"沒這回事，她老是闖禍，我就要一直幫她擦屁股！"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"GUEST_VOICE_WOMEN_NULL","text":{"KOREA":"그래도 귀여운 모모를 보려고 찾아오는 손님도 꽤나 있잖아?","JPN":"でも可愛いモモちゃんを見ようと店に来る客も結構多いだろ？","ENG":"But a lot of people come here just to see Momo. She's so cute.","TWN":"不過莫莫這麼可愛，應該也有很多客人是衝著她來的吧？"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"그분들이 주시는 과자 때문에 바닥이 어질러지는 건 덤이고 말이죠.","JPN":"その方々からもらった差し入れのせいで\\n床がお菓子の食べかすだらけなのは有難迷惑です。","ENG":"And that's why our floor is perpetually covered with food crumbs.","TWN":"那些客人都會給她餅乾，每次都吃得一地都是，嫌我事情不夠多呢～"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"GUEST_VOICE_WOMEN_NULL","text":{"KOREA":"동료 직원보단 돌봐 주는 보모 느낌이긴 하지. 니콜도 고생이 많아.","JPN":"スタッフ同士というより面倒を見てくれる保母さんのような感じだな。\\nニコルちゃんもいつもお疲れ様。","ENG":"I get that you feel as if you're babysitting her. It must be frustrating.","TWN":"妮可感覺不像是同事，反而像是顧小孩的保母呢，真是辛苦啦～"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"돌보다뇨, 누가 그런 꼬맹이 악마를…….","JPN":"面倒を見るって、誰があんなチビ悪魔を……","ENG":"I'm not babysitting her. She's just a little devil—","TWN":"誰要照顧她，那個小魔鬼……"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"악마를…….","JPN":"悪魔を……","ENG":"Devil...","TWN":"魔鬼……"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"…아아아앗?!","JPN":"……ああっ！？","ENG":"Waaah!","TWN":"…啊啊啊！"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L4_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"(까맣게 잊고 있었어요! 저는 일주일 동안 대체 뭘 하고 있었던 거죠?)","JPN":"(すっかり忘れていました！　私は一週間いったい何をしていたのでしょう？)","ENG":"(I completely forgot! What have I been doing all week?)","TWN":"(整個忘得一乾二淨！我這個禮拜到底都在幹嘛？)"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"(퇴마사가 술을 파는 것도 모자라 악마와 어울리다니! 단순징계가 아니라 파문감이라고요!)","JPN":"(エクソシストが酒を売るだけではなく、悪魔と戯れるなんて！\\n懲戒で済む話じゃなくて、破門案件ですよ！)","ENG":"(Not only have I been selling alcohol, but I've also socialized with a devil! This doesn't just call for a simple punishment—I could be excommunicated for this!)","TWN":"(身為驅魔師不只賣酒，還和魔鬼打交道！這不是懲戒可以了事的，應該會被逐出驅魔會吧！)"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"GUEST_VOICE_WOMEN_NULL","text":{"KOREA":"갑자기 왜 그래? 괜찮은 거야?","JPN":"急にどうしたんだい？　大丈夫か？","ENG":"What's wrong all of a sudden? Are you okay?","TWN":"怎麼了？你還好嗎？"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"……괘, 괜찮아요! 주문하신 거 드릴게요!","JPN":"……だ、大丈夫です！　ご注文のもの、お作りしますね！","ENG":"I-I'm fine! Let me give you your drink!","TWN":"……喔，我沒事！這是您點的琴通寧！"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"GUEST_VOICE_WOMEN_NULL","text":{"KOREA":"아……. 응.","JPN":"あ……おう。","ENG":"Erm... Okay.","TWN":"喔喔……。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"(이래선 안 돼요. 기다렸다가 돌아오는 대로 퇴마를 재개해야겠어요.)","JPN":"(こうしてはいられません。モモが戻り次第退魔を再開しなければ。)","ENG":"(It shouldn't be like this. I have to exorcise her as soon as she returns.)","TWN":"(這樣不行，等她回來後，我要重新進行驅魔儀式！)"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L14_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"(하지만 꼭 해야만 하는 걸까요?)","JPN":"(しかし必ずやるべきことなのでしょうか？)","ENG":"(But... do I really have to?)","TWN":"(可是真的有必要嗎？)"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L16_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"(모모가 제멋대로 굴고, 가게에 민폐만 끼치긴 해도, 남을 악의적으로 해코지하진 않았는데…….)","JPN":"(モモはわがままでお店に迷惑ばかりかけてはいますが、\\n人に悪意を持って害することはしていないのに……)","ENG":"(Sure, Momo is unruly and not helpful to the business, but she doesn't hurt anyone...)","TWN":"(莫莫雖然很任性，整天給店裡添麻煩，但她從來沒有害人之心……)"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"PRIEST_NPC_VATICAN_NULL","text":{"KOREA":"성자의 이름으로 세상의 모든 악마를 남김없이 처단하는 것.","JPN":"聖者の名のもとに、この世のすべての悪魔を残さず祓うこと。","ENG":"To punish all the devils in the world in the name of the Son.","TWN":"以聖者之名，驅除世界上一切的魔鬼，"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"PRIEST_NPC_VATICAN_NULL","text":{"KOREA":"그것이 구마회의 소명.","JPN":"それが祓魔会の使命。","ENG":"That's the purpose of the Exorcism Council.","TWN":"這就是驅魔會的使命。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"PRIEST_NPC_VATICAN_NULL","text":{"KOREA":"구마의 길에 십자와 성자의 축복이 있을지언정, 인류사에 이름이 남는 영광은 없을 것입니다.","JPN":"祓魔の道に十字架と聖者の祝福があったとしても、\\n人類史にその名が残る栄光はないでしょう。","ENG":"The path of the exorcist may be blessed by the Son and his crucifix, but it's not glorious.","TWN":"驅魔之路雖然有聖者的祝福，但要名留青史是不可能的。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"PRIEST_NPC_VATICAN_NULL","text":{"KOREA":"어둠 속에서 길을 밝혀주는 등불은 오로지 자매님의 신앙뿐.","JPN":"暗闇の中で道を照らす灯りは、ただシスターの信仰のみ。","ENG":"Only your faith can guide you along the path shrouded in darkness.","TWN":"能夠在黑暗中為你指引明路的，唯有你的信仰。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"PRIEST_NPC_VATICAN_NULL","text":{"KOREA":"그런데도 이 길을 걸으시렵니까?","JPN":"それでもこの道を歩むと誓いますか？","ENG":"Are you sure you want to walk this path?","TWN":"即便如此，你願意選擇這條路嗎？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"(그렇죠. 저는 맹세했어요. 구마회의 일원이 되어 모든 악마를 처단하기로.)","JPN":"(そうでした。私は誓いました。\\n祓魔会の一員となり、すべての悪魔を祓うと。)","ENG":"(That's right. I made a promise that I will punish all devils as a member of the Exorcism Council.)","TWN":"(沒錯，我發過誓的。身為驅魔會的一員，要除盡所有的魔鬼！)"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"(겉모습은 어린애지만 악마는 악마예요. 고작 이런 어설픈 연민의 감정 때문에 나약해질 순 없죠.)","JPN":"(見た目は子どもですが悪魔は悪魔です。\\nこんな生半可な憐憫のせいで本分を忘れてはいけません。)","ENG":"(She's a wolf in sheep's clothing. I must not let my foolish emotions sway me.)","TWN":"(雖然她的外表只是個孩子，但魔鬼就是魔鬼！我不能因為這種無謂的憐憫之心就心軟！)"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"하, 하수인아~!","JPN":"げ、下僕よ～！","ENG":"M-my subject!","TWN":"嗚…手下～！"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"드디어 왔군요, 이 악마! 어서 심판을……!","JPN":"やっと戻って来たんですね、この悪魔！　今すぐ裁きを……！","ENG":"Finally, you're back, devil! Get ready for your punish—","TWN":"終於回來啦！你這個魔鬼！準備接受審判……！"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL_02"},{"id":"L33_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"응? 꼴이 왜 그래요?","JPN":"うん？　その恰好はどうしたんですか？","ENG":"Mm? What happened to you?","TWN":"嗯？你怎麼這副德性？"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"으으… 사탕 가게로 가고 있었는데…","JPN":"うう……キャンディを買いに行ったら……","ENG":"Aww... I was on my way to the candy shop...","TWN":"嗚嗚…人家本來要去糖果店…"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"행색이 불량한 인간들이 뒷골목으로 날 불러서…","JPN":"不良っぽい人間たちが路地裏に吾輩を呼んで……","ENG":"when some thuggish humans called me into the back alley...","TWN":"結果在小巷子裡遇到一群小混混叫住我…"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"이 몸의 지갑을 빼앗아갔노라.","JPN":"お財布を奪っていったのだ。","ENG":"and took away my purse.","TWN":"他們就把本王的錢包搶走了啦！"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"BULLY_NPC_NULL_M","text":{"KOREA":"쳇, 뭐야. 좀 귀티 나게 생겨서 부잣집 애인 줄 알았는데 지갑에 순 동전뿐이잖아?","JPN":"ちっ、なんだよ。金持ちのガキかと思ったのに小銭しか入ってねえ。","ENG":"Bah, what is this? She looked like a rich girl, but she's only got coins in her purse.","TWN":"嘖！搞什麼，看她一副有錢人家孩子的樣子，結果錢包裡面都是零錢！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L40_1","type":"dialog","speaker":"BULLY_NPC_NULL_F","text":{"KOREA":"그나마 한 장 있던 지폐도 꼬깃꼬깃해. 어디 내밀기도 부끄럽네.","JPN":"一枚だけ入ってた紙幣もしわくちゃよ。\\nどこかで出すのも恥ずかしいくらいだわ。","ENG":"The only bill she had looks really grubby, too. I'm afraid to touch it.","TWN":"而且連唯一的一張紙鈔也皺巴巴的，拿給店家都覺得不好意思！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"거기, 당신들!","JPN":"そこのあなたたち！","ENG":"Hey, you!","TWN":"喂！我說你們！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L45_1","type":"dialog","speaker":"BULLY_NPC_NULL_M","text":{"KOREA":"응? 뭐야, 넌?","JPN":"あん？　なんだてめえは？","ENG":"Huh? Who are you?","TWN":"嗯？你誰啊？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L46_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"그 지갑 돌려 주시죠. 남의 것을 탐내면 벌 받게 되어 있어요.","JPN":"そのお財布、返してください。他人のものを欲しがると罰が当たりますよ。","ENG":"Give that purse back. You shall not covet anything that belongs to your neighbor.","TWN":"可以把錢包還來嗎？覬覦別人的東西是會受到懲罰的！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L48_1","type":"dialog","speaker":"BULLY_NPC_NULL_F","text":{"KOREA":"야, 뒤에 숨어 있는 것 좀 봐. 저 꼬맹이 보호잔가 본데?","JPN":"ねえ、後ろに隠れてるの見て。あのガキの保護者みたいよ？","ENG":"Hey, look who's behind her. Are you that kid's guardian or something?","TWN":"喂，你看躲在後面的小鬼，應該是她的家長吧？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L49_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"…힉!","JPN":"……ひッ！","ENG":"Heek!","TWN":"…嗚！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L1_1","type":"dialog","speaker":"BULLY_NPC_NULL_M","text":{"KOREA":"뭐야. 걔가 아줌마 딸이었어? 어째 닮은 구석이 하나도 없는데? 입양아인가?","JPN":"なんだ、そいつはババアの子か？　全然似てねえな。養子か？","ENG":"What, is she your daughter? But she doesn't look like you at all. Is she adopted?","TWN":"現在是怎樣？她是大嬸的女兒嗎？但我看你們長得一點都不像，是領養來的嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"우리 가게 직원의 재산을 갈취한 범죄자들 주제에 태도가 뻔뻔하네요.","JPN":"うちの店のスタッフの財産を奪った犯罪者らしく、\\nずいぶんと図々しい態度ですね。","ENG":"You stole my coworker's assets. You should be ashamed of yourselves.","TWN":"搶走我們店裡員工的財產，講話還那麼囂張！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"BULLY_NPC_NULL_F","text":{"KOREA":"푸핫, 푼돈 몇 푼 가지고 재산은 무슨.","JPN":"プッ、これっぽっちの小銭が財産ですって？","ENG":"Hah! What assets? You mean, a few coins?","TWN":"噗哈哈！幾塊錢也能稱作是財產嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"푼돈이라니, 무엄하다! 이 몸이 일해서 번 노동의 대가이니라!","JPN":"小銭だなんて、無礼者め！\\nそれは吾輩が働いて稼いだ労働の代償だ！","ENG":"A few coins? How dare you? I've worked hard for them!","TWN":"那才不是幾塊錢！大膽！那可是本王辛辛苦苦用勞力換來的！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L7_1","type":"dialog","speaker":"BULLY_NPC_NULL_F","text":{"KOREA":"이게 어른 하나 데려왔다고 까부는 것 좀 봐. 맞을래?","JPN":"大人一人連れてきたからって調子に乗るんじゃないわよ。\\nぶっ叩かれたいの？","ENG":"You're not afraid of us anymore because you're with her? You need a good beating.","TWN":"以為帶個大人來替你撐腰，講話就可以大聲了是吧？是不是想挨揍！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"흐이잉…","JPN":"ふえーん……","ENG":"Hnnggg...","TWN":"嗚嗚嗚…"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L10_1","type":"dialog","speaker":"BULLY_NPC_NULL_M","text":{"KOREA":"마침 잘됐네. 우리가 돈이 좀 필요한데, 아줌마가 용돈 좀 나눠 주라.","JPN":"ちょうどよかった。ちょっと今金が必要なんだ。ババアが金をよこせよ。","ENG":"Oh, this reminds me. We need money. Why don't you give us what you've got, lady?","TWN":"正好我們缺錢用，大嬸給點零用錢吧！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"BULLY_NPC_NULL_F","text":{"KOREA":"도망쳐 봤자 이 동네는 우리 손바닥 안이야. 처신 잘하라고.","JPN":"逃げたところでこの町は私たちの掌の上なんだよ。行動には気をつけな。","ENG":"You could run, but we own this neighborhood. You'd better think carefully.","TWN":"勸你別想逃，這附近都是我們的地盤，放聰明點！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"어린아이를 괴롭힌 것도 모자라, 협박까지 일삼다니…….","JPN":"子どもをいじめただけでは飽き足らず、脅迫までするとは……","ENG":"Not only did you bully a little girl, but now you're also threatening me.","TWN":"欺負小朋友還不夠，現在還威脅人……"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"죄의식이라고는 조금도 못 느끼는 건가요?","JPN":"罪の意識を少しも感じないのですか？","ENG":"Don't you have a conscience?","TWN":"你們都不會有罪惡感嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"당신들, 정말 구제 불능이군요.","JPN":"あなたたちは、本当に救いようがない人たちですね。","ENG":"You're incorrigible.","TWN":"我看你們根本無藥可救！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"BULLY_NPC_NULL_F","text":{"KOREA":"와, 무서워라.","JPN":"わあ怖い。","ENG":"Oooh, that's scary.","TWN":"哇，我好怕喔～"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"BULLY_NPC_NULL_M","text":{"KOREA":"아줌마가 상황 파악을 못하는구만.","JPN":"このババア、状況がわかってないようだな。","ENG":"You don't know what kind of situation you're in, do you?","TWN":"大嬸你好像搞不清楚狀況，"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L18_1","type":"dialog","speaker":"BULLY_NPC_NULL_M","text":{"KOREA":"칼침 맛 좀 봐야 세상 무서운 줄 알지!","JPN":"痛い目にあわせてやらないとな！","ENG":"Do I really have to show you how big my knife is?","TWN":"不給你點顏色瞧瞧，你還真當我們是吃素的！"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_SWORD_MOVEMENT"},{"id":"L20_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"아앗?!","JPN":"ああっ！？","ENG":"Aah!","TWN":"哇啊？！"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_RUNNING_02"},{"id":"L21_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"물러서요, 모모!","JPN":"下がってください、モモ！","ENG":"Step back, Momo!","TWN":"莫莫，你走開！"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};